import json
import os
import random
import modal
import pandas as pd

APP_NAME = "modal-nfs-etl-pipeline"
VOLUME_NAME = "modal-nfs-etl-pipeline-vol"
SECRET_NAME = "modal-nfs-etl-pipeline-secret"
DICT_NAME = "modal-nfs-etl-pipeline-output"
SHARED_PATH = "/shared"
RAW_DATA_PATH = f"{SHARED_PATH}/raw_data.csv"
TRANSFORMED_DATA_PATH = f"{SHARED_PATH}/transformed_data.csv"
REPORT_PATH = f"{SHARED_PATH}/final_report.json"

app = modal.App(APP_NAME)
image = modal.Image.debian_slim().pip_install("pandas")
volume = modal.Volume.from_name(VOLUME_NAME, create_if_missing=True)
secret = modal.Secret.from_name(SECRET_NAME)


def _get_batch_size() -> int:
    return max(10, int(os.environ.get("BATCH_SIZE", "10")))


@app.function(image=image, volumes={SHARED_PATH: volume}, secrets=[secret])
def extract() -> int:
    pipeline_id = os.environ.get("PIPELINE_ID", "unknown")
    batch_size = _get_batch_size()

    random.seed(pipeline_id)
    names = [f"user_{index:03d}" for index in range(batch_size)]
    categories = [random.choice(["alpha", "beta", "gamma"]) for _ in range(batch_size)]
    values = [random.randint(10, 100) for _ in range(batch_size)]
    scores = [round(random.uniform(0.1, 0.99), 3) for _ in range(batch_size)]

    df = pd.DataFrame(
        {
            "name": names,
            "category": categories,
            "value": values,
            "score": scores,
        }
    )
    df.to_csv(RAW_DATA_PATH, index=False)
    volume.commit()
    return len(df)


@app.function(image=image, volumes={SHARED_PATH: volume}, secrets=[secret])
def transform() -> int:
    _ = os.environ.get("PIPELINE_ID", "unknown")
    df = pd.read_csv(RAW_DATA_PATH)

    for column in df.select_dtypes(include=["object"]).columns:
        df[column] = df[column].str.upper()

    df["value_squared"] = df["value"] ** 2
    df.to_csv(TRANSFORMED_DATA_PATH, index=False)
    volume.commit()
    return len(df)


@app.function(image=image, volumes={SHARED_PATH: volume}, secrets=[secret])
def load() -> int:
    pipeline_id = os.environ.get("PIPELINE_ID", "unknown")
    df = pd.read_csv(TRANSFORMED_DATA_PATH)

    numeric_columns = df.select_dtypes(include=["number"]).columns
    aggregates = {
        column: {
            "min": float(df[column].min()),
            "max": float(df[column].max()),
            "mean": float(df[column].mean()),
        }
        for column in numeric_columns
    }

    report = {
        "pipeline_id": pipeline_id,
        "rows_processed": len(df),
        "aggregates": aggregates,
    }
    with open(REPORT_PATH, "w", encoding="utf-8") as handle:
        json.dump(report, handle, indent=2)

    volume.commit()
    return len(df)


@app.local_entrypoint()
def main() -> None:
    rows_extracted = extract.remote()
    rows_transformed = transform.remote()
    rows_loaded = load.remote()

    output_dict = modal.Dict.from_name(DICT_NAME, create_if_missing=True)
    output_dict.update(
        {
            "rows_extracted": rows_extracted,
            "rows_transformed": rows_transformed,
            "rows_loaded": rows_loaded,
            "pipeline_id": "nfs-etl-2024",
            "report_path": REPORT_PATH,
        }
    )
